example_bad:
fn main() {
    let r;
    {
        let s = String::from("hello");
        r = &s; // Error: `s` does not live long enough
    }
    println!("{}", r);
}

fixes.code:
let s = String::from("hello");
let r = &s;
println!("{}", r);

let r;
{
    let s = String::from("hello");
    r = s; // Move instead of borrow
}
println!("{}", r);
